public class Main {
    public static void main(String[] args) {
        String variable = "Hello world";
        System.out.println(variable);
    }
}

public class AssignValue {
    public static void assign(String variable, String newValue) {
        variable = newValue;
    }
}

public class Concatenate {
    public static String combine(String variable, String add) {
        return variable + add;
    }
}

public class Compare {
    public static String compare(String variable, String check) {
        return variable.equals(check) ? "equal" : "not equal";
    }
}

public class Main {
    public static void main(String[] args) {
        String variable = "Hello world";
        System.out.println(variable);
        AssignValue.assign(variable, "Java is fun");
        String result = Concatenate.combine(variable, " programming");
        String outcome = Compare.compare(variable, "Java is fun");
        System.out.println(result);
        System.out.println(outcome);
    }
}

